import { Router, type Request, type Response } from "express";
import { ServiceError } from "../services/serviceError.js";
import * as productService from "../services/productService.js";

const router = Router();

function handleError(res: Response, err: unknown): void {
  if (err instanceof ServiceError) {
    const status = err.code === "NOT_FOUND" ? 404 : 400;
    res.status(status).json({ error: err.message });
  } else {
    throw err;
  }
}

// GET /products - list all products, optionally filter by category
router.get("/products", (req: Request, res: Response) => {
  const { category, minPrice, maxPrice } = req.query;

  const filters: productService.ProductFilters = {};

  if (category && typeof category === "string") {
    filters.category = category;
  }

  if (minPrice && typeof minPrice === "string") {
    const min = parseFloat(minPrice);
    if (!isNaN(min)) filters.minPrice = min;
  }

  if (maxPrice && typeof maxPrice === "string") {
    const max = parseFloat(maxPrice);
    if (!isNaN(max)) filters.maxPrice = max;
  }

  res.json(productService.listProducts(filters));
});

// GET /products/:id
router.get("/products/:id", (req: Request, res: Response) => {
  try {
    const id = parseInt(req.params.id, 10);
    res.json(productService.getProduct(id));
  } catch (err) {
    handleError(res, err);
  }
});

// PATCH /products/:id/stock - update stock
router.patch("/products/:id/stock", (req: Request, res: Response) => {
  const { adjustment } = req.body as { adjustment: unknown };

  if (typeof adjustment !== "number") {
    res.status(400).json({ error: "adjustment must be a number" });
    return;
  }

  try {
    const id = parseInt(req.params.id, 10);
    res.json(productService.adjustStock(id, adjustment));
  } catch (err) {
    handleError(res, err);
  }
});

export { router as productRouter };

